INSERT OR REPLACE INTO regular_expressions (name, pattern, regex101_id, description) VALUES ('Colourisation', '\bcolou?r(i[sz]ed?|ed)?\b', NULL, 'Colourisation (or colorization in American English) is the process of adding colour to black-and-white, sepia, or other monochrome images. Matches variations of `color` in both American and British spellings, including:

- **Base forms:** `color`, `colour`
- **Past tense/adjective forms:** `colored`, `coloured`
- **Verb forms:** `colorize`, `colourize`, `colorise`, `colourise`
- **Past participles:** `colorized`, `coloured`, `colourized`, `colourised`');
INSERT OR IGNORE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Colourisation', 'Colour Grade');
INSERT OR IGNORE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Colourisation', 'Enhancement');
