INSERT OR REPLACE INTO regular_expressions (name, pattern, regex101_id, description) VALUES ('Crave', '\b(?:CRAV|(?:CRAVE)(?=\s*.(?:WEB-?DL|WEBRIP)))\b', NULL, 'Crave (originally CraveTV) is a Canadian subscription video on demand service. The service competes directly with other subscription-based over-the-top streaming services operating in Canada, primarily against American-based services. The service features Bell Media original programming, exclusive Canadian access to programming acquired from several U.S. television and streaming services, and various theatrically-released films. Crave''s major programming supplier is Warner Bros. Discovery (HBO / Max and Warner Bros. films). Starz, offered in partnership with Lionsgate.');
INSERT OR IGNORE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Crave', 'Streaming Service');
INSERT OR IGNORE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Crave', 'WEB-DL');
