INSERT OR REPLACE INTO regular_expressions (name, pattern, regex101_id, description) VALUES ('Crunchyroll', '\b(C(runchy)?[ .-]?R(oll)?)\b', NULL, 'Crunchyroll is a popular streaming service focused on anime, manga, and Asian entertainment. It offers a large library of animated series and films, including both classic titles and new simulcasts straight from Japan, often with subtitles soon after they air. Users can watch on demand across devices, and there’s both a free, ad-supported tier and paid premium subscriptions with ad-free viewing and early access to episodes.');
