INSERT OR REPLACE INTO regular_expressions (name, pattern, regex101_id, description) VALUES ('Dolby Vision', '\b(dv(?![ .](HLG|SDR))|dovi|dolby[ .]?vision)\b', NULL, 'Dolby Vision is a high dynamic range (HDR) video format that uses dynamic metadata to deliver enhanced brightness, contrast, and color on a scene-by-scene or frame-by-frame basis, providing superior picture quality. This pattern excludes matches where Dolby Vision is associated with SDR (Standard Dynamic Range) or HLG (Hybrid Log-Gamma), ensuring it focuses on Dolby Vision-specific terms.');
INSERT OR IGNORE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Dolby Vision', 'Enhancement');
